function solve(prices: number[], strategy: number[], k: number): number {
    let maxProfit = 0;
    const n = prices.length;

    // Calculate the original profit
    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }
    maxProfit = originalProfit;

    // Try to modify each possible subarray of length k
    for (let i = 0; i <= n - k; i++) {
        // Calculate the profit change if we modify the subarray [i, i + k - 1]
        let profitChange = 0;

        // For the first k/2 elements, change from -1 to 0 (buy to hold)
        for (let j = 0; j < k / 2; j++) {
            profitChange += (0 - strategy[i + j]) * prices[i + j];
        }

        // For the next k/2 elements, change from 1 to 1 (sell remains the same)
        // So no change here

        // Add the profit change to the original profit
        let newProfit = originalProfit + profitChange;
        if (newProfit > maxProfit) {
            maxProfit = newProfit;
        }
    }

    return maxProfit;
}

